void solve(int CASE)
{
	int n; cin >> n;
	var t = Trie();
	fa(i, 1, 2 * n) {
		string s; cin >> s;
		t.insert(s);
	}
	ll ans = 0;
	var now = t.root;
	var dfs = [&](var dfs, TrieNode* now)->void {
		for (char c = 'a'; c <= 'z'; c++) {
			if (now->children.count(c)) {
				var nex = now->children[c];
				ll cnt = t.prefixs[nex->id];
				ans += ((cnt + 1) / 2) * (cnt / 2);
				dfs(dfs, nex);
			}
		}
		};
	dfs(dfs, now);
	cout << ans << endl;

	return;
}
